<script setup lang="ts">
import { computed, reactive, ref } from 'vue'
import { useQuery, useQueryClient } from '@tanstack/vue-query'
import { Cloud, Database, Download, FileCheck2, HardDriveUpload, RefreshCw, ShieldAlert, Trash2, Upload } from '@lucide/vue'
import { api } from '../api/client'
import AppDialog from '../components/AppDialog.vue'
import AsyncButton from '../components/AsyncButton.vue'
import ConfirmDialog from '../components/ConfirmDialog.vue'
import PageHeader from '../components/PageHeader.vue'
import StateBlock from '../components/StateBlock.vue'
import { useAsyncActions } from '../composables/useAsyncActions'
import { useTaskStore } from '../stores/tasks'
import { useUIStore } from '../stores/ui'

interface Stats{subscription_count:number;download_log_count:number;local_anime_count:number;user_count:number;global_config_count:number;database_size:string;last_modified:string}
interface BackupFile{key:string;size:number;last_modified:string}
interface Progress{task_id:string;total_bytes:number;downloaded:number;status:string;error?:string;result?:{stats?:Record<string,unknown>;restore_token?:string;key?:string}}
const ui=useUIStore(),tasks=useTaskStore(),qc=useQueryClient(),actions=useAsyncActions(),file=ref<File|null>(null),analysis=ref<Record<string,unknown>|null>(null),restoreToken=ref(''),deleteKey=ref(''),restoreOpen=ref(false),stageProgress=reactive<Record<string,Progress|undefined>>({}),uploadProgress=ref<Progress|null>(null)
const categories=reactive<Record<string,boolean>>({configs:true,metadata:true,subscriptions:true,logs:true,local:true,users:false}),regenerateNFO=ref(true)
const categoryOptions=[{key:'configs',label:'系统配置'},{key:'metadata',label:'元数据'},{key:'subscriptions',label:'订阅'},{key:'logs',label:'下载日志'},{key:'local',label:'本地媒体索引'},{key:'users',label:'管理员账户'}]
const query=useQuery({queryKey:['backup'],queryFn:()=>api<{stats:Stats;r2:{configured:boolean;files:BackupFile[]}}>('/backup')})
const selectedCategories=computed(()=>Object.entries(categories).filter(([,enabled])=>enabled).map(([key])=>key))
async function uploadAnalyze(){if(!file.value)return;try{await actions.run('analyze',async()=>{const data=new FormData();data.append('backup_file',file.value!);const result=await api<{stats:Record<string,unknown>;restore_token:string}>('/backup/analyze',{method:'POST',body:data});analysis.value=result.stats;restoreToken.value=result.restore_token;restoreOpen.value=true;ui.toast('备份文件校验通过')})}catch(e){ui.toast(e instanceof Error?e.message:'分析失败','error')}}
async function restore(){if(!selectedCategories.value.length){ui.toast('请至少选择一类数据','error');return}try{await actions.run('restore',async()=>{await api('/backup/restore',{method:'POST',body:JSON.stringify({restore_token:restoreToken.value,categories:selectedCategories.value,regenerate_nfo:regenerateNFO.value}),headers:{'Content-Type':'application/json'}});ui.toast('恢复已完成');analysis.value=null;restoreOpen.value=false;qc.invalidateQueries()})}catch(e){ui.toast(e instanceof Error?e.message:'恢复失败','error')}}
async function pollProgress(taskID:string,onProgress:(progress:Progress)=>void){for(let i=0;i<180;i++){await new Promise(resolve=>setTimeout(resolve,1000));const progress=await api<Progress>(`/backup/r2/progress/${taskID}`);onProgress(progress);if(progress.status==='completed')return progress;if(progress.status==='error')throw new Error(progress.error||'云备份任务失败')}throw new Error('云备份任务等待超时，请稍后刷新查看')}
async function uploadCloud(){uploadProgress.value=null;let taskID='';try{await actions.run('cloud-upload',async()=>{const task=await api<{task_id:string}>('/backup/r2/upload',{method:'POST'});taskID=task.task_id;tasks.upsert({id:taskID,kind:'backup',title:'R2 云备份',detail:'正在创建完整备份',tone:'running'});await pollProgress(taskID,progress=>{uploadProgress.value=progress;tasks.upsert({id:taskID,kind:'backup',title:'R2 云备份',detail:progress.status==='preparing'?'正在创建完整备份':'正在上传到 R2',current:progress.downloaded,total:progress.total_bytes,tone:'running'})});tasks.upsert({id:taskID,kind:'backup',title:'R2 云备份',detail:'云备份上传完成',tone:'success'});ui.toast('云备份上传完成');qc.invalidateQueries({queryKey:['backup']})})}catch(e){if(taskID)tasks.upsert({id:taskID,kind:'backup',title:'R2 云备份',detail:e instanceof Error?e.message:'上传失败',tone:'error'});ui.toast(e instanceof Error?e.message:'上传失败','error')}}
async function deleteCloud(){const key=deleteKey.value;try{await actions.run(`delete-${key}`,async()=>{await api('/backup/r2/delete',{method:'POST',body:JSON.stringify({key}),headers:{'Content-Type':'application/json'}});ui.toast('云备份已删除');deleteKey.value='';qc.invalidateQueries({queryKey:['backup']})})}catch(e){ui.toast(e instanceof Error?e.message:'删除失败','error')}}
async function stage(key:string){stageProgress[key]=undefined;let taskID='';try{await actions.run(`stage-${key}`,async()=>{const task=await api<{task_id:string}>('/backup/r2/stage',{method:'POST',body:JSON.stringify({key}),headers:{'Content-Type':'application/json'}});taskID=task.task_id;tasks.upsert({id:taskID,kind:'backup',title:'云备份恢复',detail:'正在下载并校验备份',tone:'running'});const progress=await pollProgress(taskID,value=>{stageProgress[key]=value;tasks.upsert({id:taskID,kind:'backup',title:'云备份恢复',detail:value.status==='analyzing'?'正在校验备份':'正在下载云备份',current:value.downloaded,total:value.total_bytes,tone:'running'})});analysis.value=progress.result?.stats||{};restoreToken.value=progress.result?.restore_token||'';restoreOpen.value=true;tasks.upsert({id:taskID,kind:'backup',title:'云备份恢复',detail:'云备份下载并校验完成',tone:'success'});ui.toast('云备份下载并校验完成')})}catch(e){if(taskID)tasks.upsert({id:taskID,kind:'backup',title:'云备份恢复',detail:e instanceof Error?e.message:'暂存失败',tone:'error'});ui.toast(e instanceof Error?e.message:'暂存失败','error')}}
const percent=(progress?:Progress)=>progress?.total_bytes?Math.round(progress.downloaded/progress.total_bytes*100):0
const formatSize=(n:number)=>n>1024*1024?`${(n/1024/1024).toFixed(1)} MB`:`${Math.ceil(n/1024)} KB`
</script>

<template><div class="page-grid"><PageHeader eyebrow="DATA SAFETY" title="备份与恢复" description="先看清备份包含什么，再执行恢复；危险操作始终需要二次确认。"><a class="btn btn-primary" href="/api/v1/backup/export"><Download :size="17"/>导出完整备份</a></PageHeader><StateBlock v-if="query.isLoading.value" state="loading"/><StateBlock v-else-if="query.isError.value" state="error" title="备份状态加载失败" :retrying="query.isFetching.value" @retry="query.refetch()"/><template v-else-if="query.data.value"><section class="grid gap-4 sm:grid-cols-2 xl:grid-cols-5"><article v-for="item in [{label:'订阅',value:query.data.value.stats.subscription_count},{label:'下载与运行日志',value:query.data.value.stats.download_log_count},{label:'本地番剧',value:query.data.value.stats.local_anime_count},{label:'系统配置',value:query.data.value.stats.global_config_count},{label:'数据库大小',value:query.data.value.stats.database_size}]" :key="item.label" class="panel p-4"><Database class="text-[var(--brand)]" :size="18"/><p class="muted mt-4 text-xs font-bold">{{ item.label }}</p><strong class="mt-1 block text-xl font-black">{{ item.value }}</strong></article></section><section class="grid gap-5 xl:grid-cols-2"><article class="panel p-5 sm:p-6"><div class="flex items-center gap-3"><span class="grid h-11 w-11 place-items-center rounded-xl bg-[var(--brand-soft)] text-[var(--brand)]"><HardDriveUpload/></span><div><p class="eyebrow">LOCAL RESTORE</p><h3 class="text-xl font-black">从文件恢复</h3></div></div><p class="muted mt-4 text-sm leading-6">选择 AnimateTool 导出的 SQLite 备份。系统会先校验内容，不会立即覆盖数据。</p><label class="mt-5 grid min-h-32 cursor-pointer place-items-center rounded-2xl border-2 border-dashed border-[var(--line)] p-5 text-center"><Upload class="muted mb-2"/><strong>{{ file?.name||'选择备份文件' }}</strong><input class="sr-only" type="file" accept=".db,.sqlite" @change="file=($event.target as HTMLInputElement).files?.[0]||null"/></label><AsyncButton class="btn btn-secondary mt-4 w-full" :disabled="!file" :loading="actions.isBusy('analyze')" loading-label="正在校验…" @click="uploadAnalyze"><FileCheck2 :size="17"/>分析备份内容</AsyncButton></article><article class="panel p-5 sm:p-6"><div class="flex items-center gap-3"><span class="grid h-11 w-11 place-items-center rounded-xl bg-[var(--sky-soft)] text-[var(--sky)]"><Cloud/></span><div><p class="eyebrow">CLOUDFLARE R2</p><h3 class="text-xl font-black">云端存档</h3></div></div><div v-if="query.data.value.r2.configured" class="mt-5"><AsyncButton class="btn btn-primary w-full" :loading="actions.isBusy('cloud-upload')" loading-label="正在上传…" @click="uploadCloud"><Cloud :size="17"/>立即上传备份</AsyncButton><div v-if="query.data.value.r2.files.length" class="mt-4 divide-y divide-[var(--line)]"><div v-for="item in query.data.value.r2.files" :key="item.key" class="grid grid-cols-[auto_1fr_auto] items-center gap-3 py-3"><Database :size="18" class="text-[var(--sky)]"/><div class="min-w-0"><p class="truncate text-sm font-bold">{{ item.key }}</p><p class="muted text-xs">{{ item.last_modified }} · {{ formatSize(item.size) }}</p></div><div class="flex gap-1"><AsyncButton class="btn btn-quiet h-10 min-h-10 px-3 text-xs" :loading="actions.isBusy(`stage-${item.key}`)" loading-label="恢复中…" @click="stage(item.key)"><RefreshCw :size="14"/>恢复</AsyncButton><button class="btn btn-danger h-10 min-h-10 w-10 p-0" :disabled="actions.isBusy(`stage-${item.key}`)" @click="deleteKey=item.key" aria-label="删除云备份"><Trash2 :size="15"/></button></div><div v-if="actions.isBusy(`stage-${item.key}`)" class="col-span-3"><div class="h-2 overflow-hidden rounded-full bg-[var(--line)]"><div class="h-full bg-[var(--sky)] transition-all" :style="{width:`${percent(stageProgress[item.key])}%`}"></div></div><p class="muted mt-1 text-xs">{{ stageProgress[item.key]?.status||'准备下载' }} · {{ percent(stageProgress[item.key]) }}%</p></div></div></div><p v-else class="muted mt-8 text-center text-sm">R2 中还没有备份</p></div><div v-else class="panel-muted mt-5 p-5 text-center"><Cloud class="muted mx-auto mb-3"/><h4 class="font-extrabold">尚未配置 R2</h4><p class="muted mt-1 text-sm">在设置页添加 Endpoint、Bucket 和访问凭据。</p><RouterLink class="btn btn-secondary mt-4" to="/settings">打开设置</RouterLink></div></article></section></template>
  <AppDialog :open="restoreOpen" title="确认恢复范围" description="恢复会覆盖所选类别的当前数据。账户与配置等敏感类别默认不全部勾选。" @update:open="restoreOpen=$event"><div v-if="analysis" class="panel-muted mb-5 grid grid-cols-2 gap-3 p-4 text-sm"><div v-for="(value,key) in analysis" :key="key"><p class="muted text-xs">{{ key }}</p><strong>{{ value }}</strong></div></div><div class="grid gap-2 sm:grid-cols-2"><label v-for="item in categoryOptions" :key="item.key" class="panel-muted flex min-h-12 items-center gap-3 p-3 font-bold"><input v-model="categories[item.key]" type="checkbox" class="h-5 w-5 accent-[var(--brand)]"/>{{ item.label }}</label></div><label class="mt-4 flex min-h-12 items-center gap-3 font-bold"><input v-model="regenerateNFO" type="checkbox" class="h-5 w-5 accent-[var(--brand)]"/>恢复后重新生成 NFO</label><AsyncButton class="btn btn-danger mt-6 w-full" :disabled="!restoreToken||!selectedCategories.length" :loading="actions.isBusy('restore')" loading-label="正在恢复…" @click="restore"><ShieldAlert :size="16"/>确认恢复所选数据</AsyncButton></AppDialog>
  <ConfirmDialog :open="Boolean(deleteKey)" danger :loading="Boolean(deleteKey&&actions.isBusy(`delete-${deleteKey}`))" loading-label="删除中…" title="删除云端备份？" :description="`将永久删除 ${deleteKey}，此操作无法撤销。`" confirm-label="永久删除" @update:open="v=>{if(!v)deleteKey=''}" @confirm="deleteCloud"/>
</div></template>
